    def isSorted(arr: Array[Long]): Boolean = {
        for (i <- 0 until arr.length - 1) {
            if (arr(i) > arr(i + 1)) return false
        }
        true
    }

    if (isSorted(nums)) return 0L

    val n = nums.length

    val (nm0, full_mask) = 
        if (n == 1) {
            (1, 1L)
        } else {
            val x = (n-1).toLong
            if (x == 0) 
                (1, 1L)
            else {
                val m = x.bitLength
                val mask = if (m >= 64) -1L else ((1L << m) - 1)
                (m, mask)
            }
        }

    var ans = 0L

    for (b <- (nm0 - 1) to 0 by -1) {
        val candidate = ans | (1L << b)
        var valid = true
        val group_map = new mutable.HashMap[Long, mutable.ListBuffer[Int]]()

        for (i <- 0 until n) {
            if ((nums(i) & candidate) != candidate) {
                if (nums(i) != i) {
                    valid = false
                }
            } else {
                val x = (nums(i) & (~candidate)) & full_mask
                group_map.getOrElseUpdate(x, mutable.ListBuffer[Int]()) += i
            }
        }

        if (!valid) {
            // Skip candidate
        } else {
            val present_groups = group_map.keySet
            val visited = new mutable.HashSet[Long]()
            val components = mutable.ListBuffer[mutable.Set[Long]]()

            for (x <- present_groups if !visited.contains(x)) {
                visited.add(x)
                val comp = mutable.Set[Long]()
                comp.add(x)
                val queue = mutable.Queue[Long]()
                queue.enqueue(x)

                while (queue.nonEmpty) {
                    val cur = queue.dequeue()
                    val base = (~cur) & full_mask
                    var s = base
                    var done = false
                    while (!done) {
                        if (present_groups.contains(s) && !visited.contains(s)) {
                            visited.add(s)
                            comp.add(s)
                            queue.enqueue(s)
                        }
                        if (s == 0) {
                            done = true
                        } else {
                            s = (s - 1) & base
                        }
                    }
                }
                components += comp
            }

            var compValid = true
            for (comp <- components if compValid) {
                val idxSet = mutable.Set[Long]()
                val valSet = mutable.Set[Long]()
                for (x <- comp) {
